#include <bits/stdc++.h>
using namespace std;
int main(){
    int n;
    if(!(cin >> n)) return 0;
    vector<int> nums(n);
    for(int i = 0; i < n; i++) cin >> nums[i];
    int target; cin >> target;

    int left = 0, right = n - 1;
    int floor = -1;
    while(left <= right){
        int mid = (left + right) / 2;
        if(nums[mid] <= target){
            floor = nums[mid];
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    left = 0, right = n - 1;
    int ceil = -1;
    while(left <= right){
        int mid = (left + right) / 2;
        if(nums[mid] >= target){
            ceil = nums[mid];
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    cout << floor << " " << ceil << endl;
    return 0;
}
